class Solution:
    def minFlips(self, target):
        n = len(target)
        s = ['0'] * n
        ops = 0
        for i in range(n):
            if s[i] != target[i]:
                ops += 1
                for j in range(i, n):
                    s[j] = '1' if s[j] == '0' else '0'
        return ops

